#include "ai_factory/cuda/g2_plus_plus/interest_rate_swaps.cuh"
#include "ai_factory/common/fixed_income/nelson_siegel.hpp"
#include "ai_factory/cuda/common/runtime.cuh"
namespace ai_factory::cuda {namespace{struct Tag{};__global__ void kernel(const G2PlusPlusSwapRow*r,std::size_t n,MonteCarloOutput*o){const auto i=static_cast<std::size_t>(blockIdx.x)*blockDim.x+threadIdx.x;if(i>=n)return;const auto x=r[i];const auto&p=x.product;double a=0;for(int j=1;j<=p.payment_count;++j)a+=p.accrual_period*fixed_income::nelson_siegel_discount(p.start_time+j*p.accrual_period,x.curve.beta0,x.curve.beta1,x.curve.beta2,x.curve.tau);const double end=p.start_time+p.payment_count*p.accrual_period;const double v=p.notional*static_cast<double>(p.direction)*(fixed_income::nelson_siegel_discount(p.start_time,x.curve.beta0,x.curve.beta1,x.curve.beta2,x.curve.tau)-fixed_income::nelson_siegel_discount(end,x.curve.beta0,x.curve.beta1,x.curve.beta2,x.curve.tau)-p.fixed_rate*a);o[i]={v,0.0};}}
void price_g2_plus_plus_interest_rate_swap_cuda(const G2PlusPlusSwapRow*h,std::size_t n,MonteCarloOutput*out,CudaTiming*t){auto&w=detail::reusable_cuda_workspace<Tag,2>();auto*r=w.buffer<G2PlusPlusSwapRow>(0,n,"G2++ swap rows");auto*o=w.buffer<MonteCarloOutput>(1,n,"G2++ swap outputs");detail::check_cuda(cudaMemcpy(r,h,n*sizeof(*h),cudaMemcpyHostToDevice),"copy rows");detail::check_cuda(cudaEventRecord(w.start_event()),"start");kernel<<<static_cast<unsigned>((n+255)/256),256>>>(r,n,o);detail::check_cuda(cudaGetLastError(),"G2++ swap kernel");detail::check_cuda(cudaEventRecord(w.stop_event()),"stop");detail::check_cuda(cudaEventSynchronize(w.stop_event()),"sync");float ms=0;detail::check_cuda(cudaEventElapsedTime(&ms,w.start_event(),w.stop_event()),"elapsed");detail::check_cuda(cudaMemcpy(out,o,n*sizeof(*out),cudaMemcpyDeviceToHost),"copy outputs");if(t){t->simulation_ms=ms;t->total_ms=ms;}}
}
